const execAsync = promisify(exec);

interface SystemMetrics {
  timestamp: number;
  memoryTotal: number;
  memoryUsed: number;
  memoryFree: number;
  memoryUsagePercent: number;
  memoryEfficiency: number;
  cpuCount: number;
  cpuLoad: number;
  platform: string;
  uptime: number;
}

interface TaskMetric {
  id: string;
  type: string;
  success: boolean;
  duration: number;
  timestamp: number;
  metadata: Record<string, any>;
}

interface PerformanceMetrics {
  startTime: number;
  totalTasks: number;
  successfulTasks: number;
  failedTasks: number;
  totalAgents: number;
  activeAgents: number;
  neuralEvents: number;
}

interface Agent {
  id: string;
  name: string;
  type: string;
  status: 'active' | 'idle' | 'busy';
  activeTasks: number;
  lastActivity?: number;
}

interface SessionData {
  id: string;
  startTime: number;
  endTime?: number;
  agents: Agent[];
  tasks: any[];
  status: 'active' | 'completed' | 'paused';
}

